mapper.select:
select ifnull(a.asset_status, 'UNKNOWN') as status, count(1) as totalCount
a.del_flag = '0' and a.status = '0' ${params.dataScope}
group by ifnull(a.asset_status, 'UNKNOWN')

select count(1)


    e.operate_time is not null

        and e.operate_time >= #{beginTime}


        and e.operate_time < #{endTime}

    ${params.dataScope}

select date_format(e.operate_time, '%Y-%m-%d') as statDate,
       count(1) as totalCount


    e.operate_time is not null

        and e.operate_time >= #{beginTime}


        and e.operate_time < #{endTime}

    ${params.dataScope}

group by date_format(e.operate_time, '%Y-%m-%d')
order by statDate asc

select date_format(o.create_time, '%Y-%m-%d') as statDate,
       count(distinct o.order_id) as totalCount


    o.del_flag = '0'
    and o.create_time is not null

        and o.create_time >= #{beginTime}


        and o.create_time < #{endTime}

    ${params.dataScope}

group by date_format(o.create_time, '%Y-%m-%d')
order by statDate asc

select date_format(t.create_time, '%Y-%m-%d') as statDate,
       count(distinct t.task_id) as totalCount


    t.del_flag = '0'
    and t.create_time is not null

        and t.create_time >= #{beginTime}


        and t.create_time < #{endTime}

    ${params.dataScope}

group by date_format(t.create_time, '%Y-%m-%d')
order by statDate asc

select date_format(i.inventory_time, '%Y-%m-%d') as statDate, count(distinct i.item_id) as totalCount from asset_inventory_task_item i inner join asset_inventory_task t on t.task_id = i.task_id and t.del_flag = '0' left join asset_location scope_location on scope_location.location_id = t.target_location_id left join sys_dept scope_dept on scope_dept.dept_id = ifnull(t.target_dept_id, scope_location.dept_id) left join sys_user scope_user on scope_user.user_id = t.owner_user_id
i.inventory_time is not null and i.inventory_result is not null and i.inventory_result <> 'NORMAL'
and i.inventory_time >= #{beginTime}
and i.inventory_time < #{endTime}
${params.dataScope}
group by date_format(i.inventory_time, '%Y-%m-%d') order by statDate asc
